#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding vaccinations-checklist (15 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    preferred_name:string! \
    gender_identity:string! \
    ethnicity:string! \
    preferred_language:string! \
    interpreter_required:string! \
    gp_name:string! \
    gp_practice:string! \
    occupation:string! \
    occupation_category:string! \
    employer:string! \
    --htmx

cargo loco generate scaffold assessment_vaccination_history \
    assessment:references \
    has_vaccination_record:string! \
    record_source:string! \
    record_source_other:text! \
    previous_adverse_reaction:string! \
    adverse_reaction_details:text! \
    adverse_reaction_vaccine:string! \
    adverse_reaction_severity:string! \
    immunocompromised:string! \
    immunocompromised_details:text! \
    pregnant_or_planning:string! \
    vaccination_history_notes:text! \
    --htmx

cargo loco generate scaffold assessment_childhood_immunisations \
    assessment:references \
    mmr_dose_1:string! \
    mmr_dose_1_date:date \
    mmr_dose_2:string! \
    mmr_dose_2_date:date \
    dtp_primary_course:string! \
    dtp_primary_date:date \
    dtp_booster:string! \
    dtp_booster_date:date \
    polio_primary_course:string! \
    polio_primary_date:date \
    polio_booster:string! \
    polio_booster_date:date \
    hib_vaccine:string! \
    hib_vaccine_date:date \
    men_c_vaccine:string! \
    men_c_vaccine_date:date \
    men_acwy_vaccine:string! \
    men_acwy_vaccine_date:date \
    pcv_vaccine:string! \
    pcv_vaccine_date:date \
    childhood_immunisations_notes:text! \
    --htmx

cargo loco generate scaffold assessment_occupational_vaccines \
    assessment:references \
    hepatitis_b_course:string! \
    hepatitis_b_course_date:date \
    hepatitis_b_doses_received:int \
    hepatitis_b_antibody_level:string! \
    bcg_vaccine:string! \
    bcg_vaccine_date:date \
    bcg_scar_present:string! \
    varicella_vaccine:string! \
    varicella_vaccine_date:date \
    varicella_history:string! \
    hepatitis_a_vaccine:string! \
    hepatitis_a_vaccine_date:date \
    typhoid_vaccine:string! \
    typhoid_vaccine_date:date \
    rabies_vaccine:string! \
    rabies_vaccine_date:date \
    occupational_vaccines_notes:text! \
    --htmx

cargo loco generate scaffold assessment_travel_vaccines \
    assessment:references \
    travel_planned:string! \
    travel_destination:string! \
    travel_departure_date:date \
    travel_return_date:date \
    yellow_fever_vaccine:string! \
    yellow_fever_vaccine_date:date \
    yellow_fever_certificate:string! \
    japanese_encephalitis_vaccine:string! \
    japanese_encephalitis_date:date \
    tick_borne_encephalitis_vaccine:string! \
    tick_borne_encephalitis_date:date \
    cholera_vaccine:string! \
    cholera_vaccine_date:date \
    meningococcal_acwy_travel:string! \
    meningococcal_acwy_travel_date:date \
    malaria_prophylaxis:string! \
    malaria_prophylaxis_drug:string! \
    travel_vaccines_notes:text! \
    --htmx

cargo loco generate scaffold assessment_covid19_vaccination \
    assessment:references \
    covid_primary_course:string! \
    covid_primary_vaccine_type:string! \
    covid_dose_1_date:date \
    covid_dose_2_date:date \
    covid_booster_1:string! \
    covid_booster_1_date:date \
    covid_booster_1_type:string! \
    covid_booster_2:string! \
    covid_booster_2_date:date \
    covid_booster_2_type:string! \
    covid_autumn_booster:string! \
    covid_autumn_booster_date:date \
    total_covid_doses:int \
    covid_adverse_reaction:string! \
    covid_adverse_reaction_details:text! \
    covid19_vaccination_notes:text! \
    --htmx

cargo loco generate scaffold assessment_influenza_vaccination \
    assessment:references \
    flu_vaccine_current_season:string! \
    flu_vaccine_current_date:date \
    flu_vaccine_type:string! \
    flu_vaccine_previous_season:string! \
    flu_vaccine_annual_recipient:string! \
    flu_high_risk_group:string! \
    flu_high_risk_reason:string! \
    flu_adverse_reaction:string! \
    flu_adverse_reaction_details:text! \
    influenza_vaccination_notes:text! \
    --htmx

cargo loco generate scaffold assessment_contraindications_allergies \
    assessment:references \
    egg_allergy:string! \
    egg_allergy_severity:string! \
    gelatin_allergy:string! \
    neomycin_allergy:string! \
    latex_allergy:string! \
    yeast_allergy:string! \
    peg_polysorbate_allergy:string! \
    other_vaccine_allergies:text! \
    history_of_gbs:string! \
    gbs_details:text! \
    on_immunosuppressants:string! \
    immunosuppressant_details:text! \
    on_blood_products_recent:string! \
    blood_products_details:text! \
    live_vaccine_contraindicated:string! \
    live_vaccine_contraindication_reason:text! \
    contraindications_allergies_notes:text! \
    --htmx

cargo loco generate scaffold assessment_serology_immunity_testing \
    assessment:references \
    hep_b_surface_antibody:string! \
    hep_b_surface_antibody_level:double \
    hep_b_surface_antibody_date:date \
    varicella_igg:string! \
    varicella_igg_date:date \
    measles_igg:string! \
    measles_igg_date:date \
    rubella_igg:string! \
    rubella_igg_date:date \
    mumps_igg:string! \
    mumps_igg_date:date \
    hep_a_igg:string! \
    hep_a_igg_date:date \
    tetanus_antibody:string! \
    tetanus_antibody_date:date \
    tb_igra_result:string! \
    tb_igra_date:date \
    mantoux_result:string! \
    mantoux_induration_mm:int \
    serology_immunity_testing_notes:text! \
    --htmx

cargo loco generate scaffold assessment_schedule_compliance \
    assessment:references \
    compliance_status:string! \
    vaccines_due:text! \
    vaccines_overdue:text! \
    catch_up_plan_required:string! \
    catch_up_plan_details:text! \
    next_vaccination_date:date \
    next_vaccination_type:string! \
    occupational_health_clearance:string! \
    occupational_health_clearance_date:date \
    exposure_risk_level:string! \
    active_exposure_incident:string! \
    active_exposure_details:text! \
    consent_for_vaccination:string! \
    consent_date:date \
    schedule_compliance_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    compliance_status:string! \
    overall_risk_level:string! \
    childhood_complete:string! \
    occupational_complete:string! \
    covid_complete:string! \
    flu_current:string! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
